-- 0010: 全量同步 projects 至 cvData 現況（team-robot/audio-amplifier 分工更正、swerve 獎名英文化、
--        job-radar/team7645-cms 連結補齊、移除 auto-sanitizer）
DELETE FROM projects WHERE id = 'auto-sanitizer';

INSERT OR REPLACE INTO projects (id, zh, en, sort_order) VALUES ('job-radar', '{"id": "job-radar", "category": "大學校外作品", "title": "Job Radar — 個人化求職雷達", "period": "2026", "description": "每日自動從 104／Cake／LinkedIn／企業官網四來源聚合目標公司職缺（約 1,300 筆/天），依個人技能加權評分，產出「每日 Top 6 精選＋推薦理由」的短清單——設計上刻意從「追求覆蓋」轉向「精準判斷」。從爬蟲、評分引擎、靜態網站生成到雲端 CI/CD 全線自建，電腦關機也每天自動更新。（AI 輔助開發，Claude Code）", "tags": ["Python", "Playwright", "Cloudflare Pages", "GitHub Actions", "靜態生成"], "detail": {"purpose": "通用求職平台用「熱門度」排序，跟「我適不適合」無關。本系統以個人技能證據為中心：自動追蹤鎖定的數十家公司、用自訂權重評分排序，把「現在能投」與「畢業後才能投」分桶，並把求職計畫與畢業時程綁在一起。設計成每天自己跑、不用開電腦的工具。", "concept": "【多來源聚合】104 走逆向出的公司頁前端 API 抓全部職缺（非關鍵字搜尋避免漏抓）；Cake 用 Playwright headless 抓 JS 渲染頁；LinkedIn 走公開訪客端點；西門子官網解析 Avature ATS，四來源混排並以顏色區分。\n\n【評分引擎】每筆職缺依公司適配度×關鍵字命中×地點×經歷門檻×新人友善度加權算分，權重全外置於 config；自動排除資深職、從 JD 抽出勤時間、標記產業學歷風氣。\n\n【資料與呈現分離】爬蟲產出結構化 JSON，建置時把卡片靜態渲染進單一 HTML，前端 JS 只做過濾／搜尋／投遞狀態（localStorage）——無後端、無資料庫，純靜態檔放 CDN。", "outcome": "每日聚合 1,300+ 筆職缺，四來源、50+ 家公司。功能含階段分桶（現在可投／校徵／正職池）、公司×崗位×前瞻成長性三維排行榜、投遞追蹤、PTT 評價對應、一鍵應徵。\n\n自動化從本機 Windows 排程遷移到 GitHub Actions 雲端 cron（每日 08:30，電腦關機也跑）；敏感的個人分析頁以 Cloudflare Pages Function 做伺服器端密碼保護，公開頁零個資、可作品集展示。工程上解過 104 API 逆向、CI 部署 token 夾帶隱形字元、跨次執行的狀態持久化等問題。", "tech": [{"group": "爬蟲與聚合", "items": [{"name": "104 API 逆向", "desc": "舊版 joblist API 失效、公司頁為 SPA，逆向前端 bundle 找出現行 /api/companies/{code}/jobs 端點與代碼編碼規則"}, {"name": "多來源整合", "desc": "requests（104/LinkedIn HTTP）＋Playwright（Cake JS 渲染）＋Avature 解析（西門子官網），統一成單一卡片 schema"}]}, {"group": "評分與呈現", "items": [{"name": "個人化評分引擎", "desc": "公司適配度×關鍵字×地點×經歷×新人友善多維加權，權重外置可調；階段分桶感知畢業時程"}, {"name": "靜態生成 RWD", "desc": "建置時靜態渲染單檔 HTML，前端僅做過濾；桌機多欄、手機單欄；Medium 閱讀風排版"}]}, {"group": "自動化與安全", "items": [{"name": "雲端 CI/CD", "desc": "GitHub Actions 每日 cron 爬取→建置→wrangler 部署 Cloudflare Pages，電腦關機照跑"}, {"name": "伺服器端登入保護", "desc": "Pages Function（_worker.js）密碼保護私密分析頁，未驗證者資料不傳輸、失敗關閉"}]}], "demo": "https://job-radar-bck.pages.dev", "github": "https://github.com/Jcsk7049/job-radar"}}', '{"id": "job-radar", "category": "大學校外作品", "title": "Job Radar: Personalized Job Search Dashboard", "period": "2026 – Present", "description": "A GitHub Actions cron job aggregates target-company listings daily from four sources (104, Cake, LinkedIn, company sites — about 1,300/day), scores them against my own skill weights, and produces a daily ''Top 6 curated shortlist with reasoning'' — a deliberate shift from coverage to precise judgment. Scraper, scoring engine, static-site build, and cloud CI/CD are all self-built; it updates daily even with my laptop off. (AI-assisted development, Claude Code)", "tags": ["Python", "Playwright", "Web Scraping", "GitHub Actions", "Cloudflare Pages"], "detail": {"purpose": "Most job boards rank listings by general popularity, which has nothing to do with whether a role actually fits me. I wanted a system centered on my own skills and constraints: track the companies I''m targeting, rank them by weights I set myself, and separate \"what I can apply to as a student now\" from \"what''s only open after graduation.\"\n\nSo I built a tool that runs itself every morning at 8:30 without needing my computer on.", "concept": "Data and presentation are separated: the scraper produces structured JSON, the build step statically renders cards into a single HTML file, and the frontend JS only handles filtering, search, and saved/applied status (stored in localStorage). No backend, no database — just static files on a CDN, fast and cheap.\n\nEach source needs a different scraping approach: 104 uses a reverse-engineered company-page API (pulling \"all listings\" instead of keyword search, to avoid missing postings); Cake''s job pages are JS-rendered, so I use Playwright headless; LinkedIn uses its public guest job endpoint over plain HTTP, no login needed. The sources have different formats, so I normalize them into one card schema before merging and ranking.\n\nScoring weights (company fit, title keyword matches, commute zone, experience requirements, junior-friendliness) all live in config.json so I can tune them without touching code. Listings are also bucketed by my graduation timeline into \"apply now / campus recruiting targets / post-graduation pool\" so \"a good fit\" and \"something I can apply to right now\" don''t get conflated.", "outcome": "It updates automatically every day, pulling roughly 1,300 listings across four sources (104, Cake, LinkedIn, company sites). A few real problems I had to fix along the way:\n\n- 104''s old joblist API was discontinued, so I reverse-engineered the company-page SPA to find the current endpoint\n- LinkedIn blocks generic scrapers, so I switched to its public guest endpoint to get around the login wall\n- It originally ran on a local Windows scheduled task, which meant nothing happened if my computer was off — moved it to GitHub Actions cron\n- CI deploys started failing because the Cloudflare token had invisible characters in it; fixed by stripping non-printable characters with tr -cd and printing the string length to diagnose\n- Telling \"is this a new listing\" apart required remembering what I''d seen across runs, solved by committing seen_jobs.json to version control\n\nPersonal academic data (graduation credits, application strategy) lives behind a login-protected page; the public job radar and rankings pages don''t contain personal data.", "tech": [{"group": "Data Collection", "items": [{"name": "104 API reverse engineering", "desc": "After the old joblist API was discontinued, found the current /api/companies/{code}/jobs endpoint and company-code scheme from the company-page SPA''s frontend bundle, pulling all listings instead of keyword search"}, {"name": "Playwright dynamic rendering", "desc": "Cake''s job pages are JS-rendered, so I use a headless browser and wait for content to load before scraping"}, {"name": "LinkedIn guest endpoint", "desc": "Uses LinkedIn''s public guest job API (plain HTTP) to avoid the login wall and typical scraper blocks"}]}, {"group": "Scoring & Presentation", "items": [{"name": "Externalized scoring engine", "desc": "Company fit, title keywords, location, experience thresholds, etc. all live in config.json, so ranking changes don''t require code edits"}, {"name": "Static dashboard generation", "desc": "build_dashboard.py normalizes the three sources'' JSON into one card schema and renders a single responsive HTML file; frontend JS only handles filtering/search/saved status (localStorage)"}]}, {"group": "Automation & Deployment", "items": [{"name": "GitHub Actions cron", "desc": "A daily cron runs the full pipeline (scrape -> score -> build -> deploy); migrated from a local Windows scheduled task so it still runs with the computer off"}, {"name": "CI deploy debugging", "desc": "A Cloudflare deploy token with invisible characters was breaking request headers; fixed by stripping non-printable characters with tr -cd before deploy and printing the string length to diagnose"}]}], "demo": "https://job-radar-bck.pages.dev", "github": "https://github.com/Jcsk7049/job-radar"}}', 0);
INSERT OR REPLACE INTO projects (id, zh, en, sort_order) VALUES ('analog-ic-studio', '{"id": "analog-ic-studio", "category": "大學校外作品", "title": "Analog IC Studio — 類比 IC 自動調參平台", "period": "2026", "description": "Python + Ngspice + SciPy 打造的類比 IC 自動化設計平台：輸入規格目標，演算法閉環模擬並自動回推每顆電晶體的 W/L，輸出可填回 KiCad 的元件參數。（AI 輔助開發）", "tags": ["Python", "Ngspice", "sky130 PDK", "SciPy", "Flask"], "detail": {"purpose": "類比 IC 設計傳統上仰賴工程師手動調參、反覆試錯。本平台將此流程自動化：使用者只要輸入規格目標（如增益 60dB、振盪頻率 3GHz、溫漂最小化），系統透過 Ngspice 真實電路模擬 + SciPy 多變量最佳化，自動回推每顆 MOS 電晶體的寬度 W 與長度 L，並輸出可一對一填回 KiCad 的元件參數。\n\n涵蓋六大電路拓樸（兩級 OPA、Bandgap 基準源、環形振盪器、電流飢餓 VCO、LC 壓控振盪器），並提供快速 Level-1 模型與 SkyWater sky130 真實 PDK 雙模式對照，兼顧迭代速度與製程真實度。", "concept": "【模擬引擎】以 Ngspice 為核心，AC/DC/瞬態分析自動萃取 Gain/PM/UGF、溫漂 TC、振盪頻率等指標，並接上 SkyWater sky130 開源 PDK（BSIM4 真實製程模型，含 tt/ff/ss 角落）。自我修復護欄偵測不收斂自動重試，區分 flaky 崩潰與確定性死區。\n\n【最佳化演算法】每顆電晶體獨立 W/L（OPA 10 維、VCO 14 維），以 SciPy Differential Evolution 全域搜尋 + Nelder-Mead 局部精調、多線程平行評估。物理護欄強制 Wp = 2~3×Wn（電子/電洞遷移率比），杜絕非物理解。\n\n【RFIC 與良率分析】相位雜訊（Leeson 解析估算）、FTR 調諧曲線與 Kvco 提取、蒙地卡羅良率採 Pelgrom 失配模型（σ ∝ 1/√WL，大元件更匹配）、PVT 27 角落掃描、帕雷托多目標套餐推薦、佈局 finger 拆分（單指 ≤ 10µm）。", "outcome": "六大拓樸全部實體化為 per-instance W/L，消除黑箱。OPA 自動優化達 Gain 65dB / PM 63°；Bandgap 溫漂 trim 至 2 ppm/°C；LC-VCO 相位雜訊 FoM −186 dBc/Hz（優於環形約 18dB，具體演示 LC vs Ring 的相位雜訊／調諧範圍取捨）。\n\n前端為 Apple 風格單頁看板（中文 UI、英文圖表標籤），含即時優化進度條；以 Docker 部署至 Hugging Face Spaces（apt ngspice + Flask），永久公開、雲端即可跑真實模擬。\n\n工程上系統性盤點並修復 13 項物理／工程缺陷（假良率模型、相位 wrap、元件自負載效應、快慢模型精細度倒置等），並誠實標註簡化邊界（相位雜訊為解析估算、LC 電感理想化），不誇大模擬能力。", "tech": [{"group": "模擬引擎", "items": [{"name": "Ngspice 閉環模擬", "desc": "AC/DC/瞬態自動萃取 Gain/PM/UGF、溫漂、振盪頻率；自我修復護欄偵測不收斂自動重試"}, {"name": "sky130 真實 PDK", "desc": "接 SkyWater sky130 開源製程（BSIM4），含 tt/ff/ss 角落，與 Level-1 快速模型雙模對照"}]}, {"group": "最佳化演算法", "items": [{"name": "多變量混合優化", "desc": "每顆 MOS 獨立 W/L（最多 14 維），SciPy DE 全域 + Nelder-Mead 局部，多線程平行評估"}, {"name": "物理護欄", "desc": "強制 Wp=2~3×Wn（遷移率比）杜絕非物理解；Pelgrom 失配良率模型 σ∝1/√WL"}]}, {"group": "RFIC 分析與部署", "items": [{"name": "RFIC 看盤", "desc": "相位雜訊（Leeson）、FTR 調諧曲線、Kvco、PVT 27 角落、帕雷托套餐、佈局 finger 拆分"}, {"name": "雲端部署", "desc": "Docker（apt ngspice + Flask）部署至 Hugging Face Spaces，永久公開、雲端跑真實模擬"}]}], "github": "https://github.com/Jcsk7049/analog-ic-studio", "demo": "https://huggingface.co/spaces/LANCELOT7049/analog-ic-studio"}}', '{"id": "analog-ic-studio", "category": "大學校外作品", "title": "Analog IC Studio — Automated Analog IC Tuning Platform", "period": "2026", "description": "A Python + Ngspice + SciPy platform that automates analog IC design: enter spec targets and the optimizer closes the loop in simulation to back-solve each transistor''s W/L. (AI-assisted development)", "tags": ["Python", "Ngspice", "sky130 PDK", "SciPy", "Flask"], "detail": {"purpose": "Analog IC design traditionally relies on manual, trial-and-error tuning. This platform automates it: the user enters spec targets (e.g. 60dB gain, 3GHz oscillation, minimal temperature drift), and the system uses real Ngspice circuit simulation plus SciPy multi-variable optimization to back-solve every MOSFET''s width W and length L, emitting device parameters that map one-to-one back into KiCad.\n\nIt covers six circuit topologies (two-stage OPA, bandgap reference, ring oscillator, current-starved VCO, LC-VCO) and offers a fast Level-1 model alongside the real SkyWater sky130 PDK, balancing iteration speed against process fidelity.", "concept": "[Simulation engine] Ngspice at the core: AC/DC/transient analyses auto-extract Gain/PM/UGF, temperature coefficient, oscillation frequency, backed by the SkyWater sky130 open PDK (BSIM4 real process models with tt/ff/ss corners). A self-healing guard detects non-convergence and retries, distinguishing flaky crashes from deterministic dead zones.\n\n[Optimization] Each transistor gets its own W/L (up to 14 dimensions); SciPy Differential Evolution for global search plus Nelder-Mead for local refinement, evaluated in parallel across threads. A physics guard enforces Wp = 2-3x Wn (electron/hole mobility ratio) to reject non-physical solutions.\n\n[RFIC & yield] Phase noise (Leeson estimate), FTR tuning curve and Kvco extraction, Monte-Carlo yield with a Pelgrom mismatch model (sigma proportional to 1/sqrt(WL), so larger devices match better), 27-corner PVT scan, Pareto multi-objective packages, and layout finger splitting (single finger <= 10um).", "outcome": "All six topologies were fully parameterized to per-instance W/L, eliminating black boxes. Auto-optimization reaches Gain 65dB / PM 63° for the OPA; the bandgap trims to 2 ppm/°C; the LC-VCO achieves phase-noise FoM -186 dBc/Hz (~18dB better than the ring, concretely demonstrating the LC-vs-ring phase-noise/tuning-range trade-off).\n\nThe frontend is an Apple-style single-page dashboard (Chinese UI, English chart labels) with a live optimization progress bar; deployed via Docker to Hugging Face Spaces (apt ngspice + Flask) for a permanent, publicly runnable demo.\n\nEngineering-wise, 13 physics/engineering defects were systematically audited and fixed (fake yield model, phase wrapping, device self-loading, fast-vs-accurate fidelity inversion, etc.), with simplification boundaries honestly labeled (phase noise is an analytical estimate; the LC inductor is idealized) rather than overstating the simulation''s capability.", "tech": [{"group": "Simulation Engine", "items": [{"name": "Ngspice closed-loop", "desc": "AC/DC/transient auto-extract Gain/PM/UGF, drift, frequency; self-healing guard retries on non-convergence"}, {"name": "Real sky130 PDK", "desc": "SkyWater sky130 open process (BSIM4) with tt/ff/ss corners, paired with a fast Level-1 model"}]}, {"group": "Optimization", "items": [{"name": "Multi-variable hybrid", "desc": "Per-instance W/L (up to 14-D), SciPy DE global + Nelder-Mead local, parallel multi-threaded eval"}, {"name": "Physics guard", "desc": "Enforces Wp=2-3x Wn (mobility ratio); Pelgrom mismatch yield model, sigma ~ 1/sqrt(WL)"}]}, {"group": "RFIC & Deployment", "items": [{"name": "RFIC dashboard", "desc": "Phase noise (Leeson), FTR tuning curve, Kvco, 27-corner PVT, Pareto packages, finger splitting"}, {"name": "Cloud deploy", "desc": "Docker (apt ngspice + Flask) on Hugging Face Spaces; permanent, runs real simulation in the cloud"}]}], "github": "https://github.com/Jcsk7049/analog-ic-studio", "demo": "https://huggingface.co/spaces/LANCELOT7049/analog-ic-studio"}}', 1);
INSERT OR REPLACE INTO projects (id, zh, en, sort_order) VALUES ('vap', '{"id": "vap", "cover": "/images/vap/cover-ai.jpg", "category": "大學專題作品", "title": "ICU VAP 早期預測：試驗性方法論驗證研究", "period": "2025 – 現在", "description": "單中心試驗性方法論驗證（亞東紀念醫院 ICU，n=109）。核心貢獻：識別 PREDICT 2025 基準採 Window-level CV 造成的 Patient-Level Data Leakage，改以 Stay-Level 5-Fold Stratified CV 建立無洩漏評估；Integrated Gradients 消除數學共線冗餘特徵（mv_total，mv≡Vt×RR），從 14 項篩選至 4 項非侵入指標，最終於亞東資料達 AUROC 0.98–0.99。研究定位：試驗性方法論驗證，非臨床部署產品。", "badge": "IEEE GCCE 2026 · Under Review", "tags": ["LSTM · Time-Series", "Integrated Gradients", "Stay-Level CV", "SMOTE", "Medical AI"], "detail": {"images": [{"src": "/images/vap/fig-pipeline.png", "caption": "系統流程：特徵篩選 → 滑動視窗 → LSTM → 多時程評估"}, {"src": "/images/vap/fig-lstm-vs-baseline.png", "caption": "Fig. 1　LSTM vs 傳統 ML 基準（AUROC / AUPRC / Sensitivity / Specificity）"}, {"src": "/images/vap/fig-lstm-performance.png", "caption": "Fig. 2　LSTM 4-feat 各預警時程效能（6–72 h）"}], "purpose": "VAP 發生率約 5–15%（機械通氣病患），死亡率 20–50%，臨床診斷通常滯後 48 小時以上；現行方法依賴定期評估，無法利用連續監測訊號的時序趨勢。\n\n本研究以亞東紀念醫院 ICU 2019–2023 年資料（n=109：VAP 54 例、非VAP 55 例），建立 LSTM 時序分類管線，以 4 項常規生命徵象（MAP、呼吸速率、潮氣容積、SpO₂）提前 6–72 小時預警 VAP。\n\n模型選擇：LSTM vs GRU / Transformer\nVAP 生理變化呈連續時序漂移（感染前 48–72 小時可見），靜態特徵不足以捕捉長程依賴。LSTM cell state 在 72 小時窗口下梯度穩定性優於 GRU；Transformer 在 n=109 小樣本下過擬合，對比測試均不及 LSTM。最終確立 LSTM 為主模型，在所有窗口 AUROC / AUPRC 均顯著高於 LR、RF、SVM。\n\n【研究侷限與誠實邊界】\n本研究是試驗性方法論驗證，非臨床可部署系統。三項核心限制：(1) 單中心資料（亞東紀念醫院），泛化至其他 ICU 族群的能力尚未建立。(2) 小樣本（n=109）——研究結果證明了 Stay-Level CV 方法論的有效性，不應被解讀為部署級臨床效能的依據。(3) 在考慮任何臨床應用前，需於多中心、更大樣本的資料集上完成外部驗證。本地資料的高 AUROC 反映的是嚴格防洩漏實驗設計在小型同質樣本上的結果。", "concept": "【一、論文復刻與資料洩漏發現】\n以 PREDICT 論文（JCM 2025）為基礎，使用 MIMIC-IV 公開資料集完整復刻其 LSTM 三層架構。復刻過程中發現原論文採用 Window-level Cross Validation——同一病患的時間窗口同時出現在訓練與測試集，造成 AUROC 虛高至 0.99，屬 Data Leakage。此發現為本研究的核心貢獻之一。\n\n【二、正確驗證方法建立】\n將切割方式改為 Stay-level Cross Validation（以病患為單位切分），消除洩漏後於 MIMIC-IV 上得到真實效能（AUROC ≈ 0.58），驗證了論文結果的侷限性。隨後以亞東紀念醫院 ICU 資料（2019–2023 年，納入 110 人，排除機械通氣時間不足 72 小時者 1 例，有效 109 人：VAP 54 例、非VAP 55 例；VAP 組入院 APACHE II 顯著較高：25.9 vs 20.1，p＜0.001）進行本地訓練；各折僅在訓練集內套用 SMOTE（1:10），確保過採樣不跨越訓練 / 測試邊界。\n\n【三、特徵工程與可解釋性】\n對 14 個生理與通氣特徵進行 Integrated Gradients（IG）歸因分析，篩選出最具預測力的 Top 4 特徵：MAP（平均動脈壓）、Vent Rate（呼吸器設定頻率）、Tidal Volume（潮氣容積）、SpO₂（血氧飽和度）。進一步透過 Ablation Study 驗證各特徵不可取代性。\n\n【四、技術架構】\n・模型：LSTM × 3 層（各 50 units）+ Dropout，二元分類輸出\n  ─ 深度選擇依據：2 層在長窗口（72 h）下梯度消失明顯；4 層在小樣本下過擬合，3 層為最佳平衡點\n・輸入：24 小時滑動視窗 × 4 特徵，逐小時滑動\n・框架：TensorFlow / Keras + GPU（NVIDIA RTX 4080 Laptop）\n・可解釋性：Integrated Gradients（積分梯度法）\n・對比基準：Logistic Regression、Random Forest、SVM（同設定公平比較）", "outcome": "【模型效能（亞東紀念醫院，Stay-level 5-fold CV）】\n\n預警時間　　　AUROC　 AUPRC　 Sensitivity　Specificity\n提前  6 小時　0.9800　0.8136　78.95%　　　99.83%\n提前 12 小時　0.9817　0.8565　81.06%　　　99.71%\n提前 24 小時　0.9919　0.9325　88.72%　　　99.64%\n提前 48 小時　0.9908　0.9352　87.46%　　　99.18%\n提前 72 小時　0.9865　0.9210　86.34%　　　98.67%\n\n模型在 24 小時預測窗口達到最佳平衡（AUROC=0.99），提前一天警示臨床人員採取防護措施。同樣設定下，LSTM 在所有窗口皆顯著優於 LR、RF、SVM 等傳統模型。\n\n【核心特徵（Top 4，IG 分析）】\n・MAP（平均動脈壓）\n・Vent Rate（呼吸器設定頻率）\n・Tidal Volume（潮氣容積）\n・SpO₂（血氧飽和度）\n\n【研究貢獻】\n・台灣本土化資料：首個以台灣 ICU 真實資料驗證的 VAP 預測模型\n・延長預測窗口：突破文獻常見的 24 小時限制，達成 72 小時超前預警\n・嚴謹驗證設計：Stay-level CV + Per-fold 正規化，確保泛化能力，杜絕 Data Leakage\n・輕量化特徵組合：僅 4 個常規監測指標，無需額外侵入性檢查\n・臨床可解釋性：IG 分析呈現模型判斷依據，提升醫師信任度\n\n【消融實驗：mv_total 排除驗證】\nmv_total（分鐘通氣量）IG 歸因排名第一（0.00989），但因 mv≡Vt×RR 為數學冗餘特徵，移除後 24 小時 AUROC 反升 +0.004、AUPRC 升 +0.014，確認冗餘特徵應以模型行為驗證，而非單憑歸因分數決定取捨。\n\n📄 論文題目：基於 Stay-Level 交叉驗證與延長預測窗口之 LSTM 呼吸器相關肺炎早期預測研究\n論文完稿（2026.05），已投稿 IEEE GCCE 2026", "tech": [{"group": "深度學習", "items": [{"name": "LSTM 時序建模", "desc": "獨立設計 3 層 LSTM（各 50 units）+ Dropout 架構，掌握時序窗口切割、Dropout 正則化與超參數調整；以 TensorFlow / Keras 實作完整訓練迴圈"}, {"name": "類別不平衡處理", "desc": "各折訓練集內套用 SMOTE（1:10），理解過採樣必須在切分後執行的 Data Leakage 邊界；資料集整體近乎平衡（54 VAP：55 非VAP），但各折訓練子集比例仍有波動，SMOTE 確保每折訓練穩定"}, {"name": "可解釋 AI（XAI）", "desc": "以 Integrated Gradients 歸因各特徵對每筆預測的貢獻，進而設計 Ablation Study 驗證 Top 4 特徵的不可取代性"}]}, {"group": "實驗設計", "items": [{"name": "防洩漏驗證設計", "desc": "自行設計 Stay-level CV（以病患為單位切分），解決原論文 Window-level CV 造成同一病患橫跨訓練/測試集的 Data Leakage；於 MIMIC-IV 復刻實驗中，AUROC 從虛高 0.99 降至真實 0.58，證實原論文結果為 Data Leakage 假象（本研究於亞東醫院資料上以相同方法從一開始即達 AUROC 0.98–0.99，詳見研究成果）"}, {"name": "Per-fold 正規化", "desc": "每折獨立計算 mean/std 後再正規化，避免測試集統計量滲漏進訓練過程，掌握正規化與切分順序的嚴謹性邊界"}, {"name": "Ablation Study", "desc": "移除 IG 排名第一的 mv_total（mv≡Vt×RR 數學冗餘），24h AUROC 反升 +0.004、AUPRC 升 +0.014，驗證特徵重要度應以模型行為而非歸因分數單一判斷；Cdyn（第11名）與 ΔP（第13名）歸因偏低一併排除"}]}, {"group": "特徵工程", "items": [{"name": "滑動視窗建構", "desc": "以 24 小時固定長度逐小時滑動，處理不等長 ICU 時序記錄的窗口對齊與邊界截斷問題"}, {"name": "生理訊號前處理", "desc": "帶通濾波、Z-score 標準化、缺失值插補，確保連續監測資料輸入品質；以 pandas / NumPy 實作 ETL 管線"}]}], "github": ""}}', '{"id": "vap", "cover": "/images/vap/cover-ai.jpg", "category": "大學專題作品", "title": "ICU VAP Prediction: Pilot Methodology Validation", "period": "2025 – Present", "description": "Pilot methodology validation on a single-center ICU dataset (Far Eastern Memorial Hospital, n=109). Core contribution: identified patient-level data leakage from window-level CV in the PREDICT 2025 baseline and established a leakage-free evaluation with Stay-Level 5-Fold Stratified CV. Integrated Gradients eliminated co-linear redundancy (mv_total where mv≡Vt×RR), distilling 14 features to 4 non-invasive metrics, reaching AUROC 0.98–0.99 on the FEMH data. Scope: single-center pilot — rigorous methodology validation, not a clinical deployment product.", "badge": "IEEE GCCE 2026 · Under Review", "tags": ["LSTM · Time-Series", "Integrated Gradients", "Stay-Level CV", "SMOTE", "Medical AI"], "detail": {"images": [{"src": "/images/vap/fig-pipeline.png", "caption": "Pipeline: feature selection → sliding window → LSTM → multi-horizon evaluation"}, {"src": "/images/vap/fig-lstm-vs-baseline.png", "caption": "Fig. 1  LSTM vs. traditional ML baselines (AUROC / AUPRC / Sensitivity / Specificity)"}, {"src": "/images/vap/fig-lstm-performance.png", "caption": "Fig. 2  LSTM 4-feat performance across warning horizons (6–72 h)"}], "purpose": "VAP incidence is ~5–15% in mechanically ventilated patients with 20–50% mortality, and clinical diagnosis typically lags 48+ hours behind onset. Current methods rely on periodic assessment and cannot leverage the temporal trends available from continuous monitoring.\n\nUsing Far Eastern Memorial Hospital ICU data (2019–2023, n=109: VAP 54, non-VAP 55), we built an LSTM time-series classification pipeline using 4 routine vital signs (MAP, respiratory rate, tidal volume, SpO₂) to provide 6–72 hour early warning of VAP.\n\nModel selection — LSTM vs. GRU/Transformer:\nVAP physiological changes exhibit continuous temporal drift (visible 48–72 hours before infection onset), so static features are insufficient to capture long-range dependencies. LSTM cell state shows better gradient stability than GRU on 72-hour windows; Transformer overfits on the n=109 small dataset. LSTM achieved consistently higher AUROC/AUPRC than LR, RF, and SVM across all windows.\n\n[Study Limitations & Honest Scope]\nThis project is a pilot methodology validation, not a production clinical system. Key constraints: (1) Single-center dataset from Far Eastern Memorial Hospital only — generalizability to other ICU populations is not yet established. (2) Small sample size (n=109) — results demonstrate the effectiveness of Stay-Level CV as a validation methodology; they should not be interpreted as evidence of deployment-ready clinical performance. (3) External validation on a multi-center, larger dataset is required before any clinical deployment consideration. The high AUROC on local data reflects a well-controlled, leakage-free experimental design applied to a small homogeneous cohort.", "concept": "[1. Paper Replication & Data Leakage Discovery]\nBased on the PREDICT paper (JCM 2025), we fully replicated its 3-layer LSTM architecture using the MIMIC-IV public dataset. During replication, we discovered that the original paper used Window-level Cross Validation — the same patient''s time windows appeared in both training and test sets, inflating AUROC to 0.99. This data leakage finding is one of the core contributions of this research.\n\n[2. Correct Validation Methodology]\nSwitching to Stay-level Cross Validation (patient-wise splitting) eliminated the leakage and revealed true performance (AUROC ≈ 0.58) on MIMIC-IV, confirming the limitations of the original paper''s results.\n\nFor the local Far Eastern ICU dataset (2019–2023, 110 enrolled, 1 excluded for <72h ventilation, effective n=109: VAP 54, non-VAP 55; VAP group had significantly higher APACHE II on admission: 25.9 vs 20.1, p<0.001), SMOTE (1:10) was applied within each training fold only, ensuring oversampling did not cross train/test boundaries.\n\n[3. Feature Engineering & Interpretability]\n14 physiological and ventilation features were analyzed with Integrated Gradients (IG), yielding the top 4 most predictive features: MAP (mean arterial pressure), Vent Rate (ventilator set rate), Tidal Volume, SpO₂. Ablation studies further validated the indispensability of each.\n\n[4. Technical Architecture]\n- Model: 3-layer LSTM (50 units each) + Dropout, binary classification output\n  (Depth rationale: 2 layers show gradient vanishing on 72h windows; 4 layers overfit on small samples; 3 layers is optimal)\n- Input: 24-hour sliding window × 4 features, sliding by 1 hour\n- Framework: TensorFlow/Keras + GPU (NVIDIA RTX 4080 Laptop)\n- Interpretability: Integrated Gradients\n- Baselines: Logistic Regression, Random Forest, SVM (same settings, fair comparison)", "outcome": "[Model Performance — Far Eastern ICU, Stay-level 5-fold CV]\n\nHorizon      AUROC    AUPRC    Sensitivity  Specificity\n6 hours      0.9800   0.8136   78.95%       99.83%\n12 hours     0.9817   0.8565   81.06%       99.71%\n24 hours     0.9919   0.9325   88.72%       99.64%\n48 hours     0.9908   0.9352   87.46%       99.18%\n72 hours     0.9865   0.9210   86.34%       98.67%\n\nThe model achieves its best balance at the 24-hour prediction window (AUROC=0.99), alerting clinicians one full day in advance. LSTM significantly outperforms LR, RF, and SVM across all windows.\n\n[Core Features — Top 4, IG Analysis]\n- MAP (Mean Arterial Pressure)\n- Vent Rate (Ventilator Set Rate)\n- Tidal Volume\n- SpO₂ (Oxygen Saturation)\n\n[Research Contributions]\n- Taiwan-localized data: first VAP prediction model validated on real Taiwan ICU data\n- Extended prediction window: beyond the 24h literature limit, achieving 72h early warning\n- Rigorous validation: Stay-level CV + per-fold normalization to prevent data leakage\n- Lightweight feature set: only 4 routine monitoring indicators, no invasive procedures\n- Clinical interpretability: IG analysis surfaces model reasoning to build physician trust\n\n[Ablation Study: mv_total exclusion]\nmv_total (minute ventilation) ranked #1 in IG attribution (0.00989) but is mathematically redundant (mv≡Vt×RR). Removing it actually improved 24h AUROC by +0.004 and AUPRC by +0.014, confirming that feature importance should be validated by model behavior, not attribution scores alone.\n\n📄 Paper: \"LSTM-Based Early Prediction of Ventilator-Associated Pneumonia Using Stay-Level Cross-Validation and Extended Prediction Windows\"\nManuscript submitted to IEEE GCCE 2026 (2026.05)", "tech": [{"group": "Deep Learning", "items": [{"name": "LSTM Time-Series Modeling", "desc": "Independently designed 3-layer LSTM (50 units each) + Dropout; implemented complete TensorFlow/Keras training loop with sliding window design, dropout regularization, and hyperparameter tuning"}, {"name": "Class Imbalance Handling", "desc": "SMOTE (1:10) applied within each training fold; understanding that oversampling must be performed after splitting to prevent data leakage across boundaries"}, {"name": "Explainable AI (XAI)", "desc": "Integrated Gradients to attribute each feature''s contribution per prediction, combined with ablation studies to validate the indispensability of the Top 4 features"}]}, {"group": "Experimental Design", "items": [{"name": "Leakage-Free Validation", "desc": "Self-designed Stay-level CV (patient-wise splits) to address window-level CV leakage in the original paper; in a MIMIC-IV replication, AUROC dropped from an inflated 0.99 to a true 0.58, confirming the original result was a leakage artifact (this study''s own model, using the same approach on FEMH data from the start, reached AUROC 0.98-0.99 — see Results)"}, {"name": "Per-fold Normalization", "desc": "Independent mean/std computed per fold before normalization, preventing test set statistics from contaminating training — mastering the strict ordering of normalization and splitting"}, {"name": "Ablation Study", "desc": "Removing IG-top-ranked mv_total (mathematically redundant: mv≡Vt×RR) improved 24h AUROC +0.004 and AUPRC +0.014, validating that model behavior — not attribution scores alone — should determine feature selection"}]}, {"group": "Feature Engineering", "items": [{"name": "Sliding Window Construction", "desc": "Fixed 24-hour windows sliding hourly, handling variable-length ICU time-series with window alignment and boundary truncation"}, {"name": "Physiological Signal Preprocessing", "desc": "Band-pass filtering, Z-score normalization, missing-value imputation for continuous monitoring data quality; ETL pipeline implemented with pandas/NumPy"}]}], "github": ""}}', 2);
INSERT OR REPLACE INTO projects (id, zh, en, sort_order) VALUES ('aws-hackathon', '{"id": "aws-hackathon", "cover": "/images/AWS-bito-guard/dashboard-cover.png", "category": "大學校外作品", "title": "AWS x BitoPro 黑客松：BitOGuard", "period": "2026", "description": "XGBoost / LightGBM × S3 → Glue → Athena → SageMaker → Lambda → Bedrock 六服務端對端 AML 管線；63,770 帳戶 / 413,235 筆交易，31 項行為特徵（含圖論黑名單鄰居）+ SHAP 合規報告識別人頭帳戶，Streamlit 儀表板已部署上線。", "tags": ["XGBoost", "LightGBM", "AWS SageMaker", "AWS Glue", "SHAP", "Streamlit"], "detail": {"images": [{"src": "/images/AWS-bito-guard/dashboard-overview.png", "caption": "數據總覽：AUC 83.2%、Precision 27.5%、Recall 33.2%，混淆矩陣 + 5-Fold CV 柱狀圖"}, {"src": "/images/AWS-bito-guard/dashboard-risk-query.png", "caption": "帳號風險查詢：USER ID 971465 評分 82.1%，判定極高風險、標記黑名單"}, {"src": "/images/AWS-bito-guard/dashboard-risk-table.png", "caption": "風險排名：Top 50 高風險帳號（CRITICAL）與 Top 50 低風險帳號對比"}, {"src": "/images/AWS-bito-guard/dashboard-model-eval.png", "caption": "模型評估：特徵重要性（total_volume 最高）+ 決策門檻分析（最佳門檻 0.24）"}, {"src": "/images/AWS-bito-guard/dashboard-predictions.png", "caption": "預測結果：12,753 位用戶，501 筆標記風險（3.93%）、12,252 筆正常（96.07%）"}], "purpose": "BitoPro 加密貨幣交易所 AML 合規競賽資料集：\n・用戶資料：63,770 筆帳戶\n・台幣轉帳紀錄：195,601 筆（56,111 用戶）\n・USDT 交易紀錄：217,634 筆（33,587 用戶）\n・標記人頭帳戶：1,640 筆（訓練集 3.21%）\n\n目標是對每個帳戶輸出風險分數，識別高風險可疑帳戶，同時滿足監管機構對 AML 合規說明的可解釋性要求（不接受黑盒輸出）。\n\n選用 XGBoost 而非深度學習的理由：AML 合規場景要求對每筆標記帳戶提供特徵層級的判斷依據，XGBoost + SHAP 可直接輸出個別帳戶的特徵貢獻值；在 <65K 結構化資料規模下，訓練速度與超參數穩定性亦優於神經網路。", "concept": "【為何選用 XGBoost，而非深度學習？】\nAML 合規系統的核心需求是可解釋性：監管機構要求對每筆標記帳戶提供「哪些特徵觸發高風險」的具體依據，而非黑盒分數。XGBoost 配合 SHAP 值分析可直接輸出每個特徵對單一帳戶預測的貢獻量，滿足合規說明義務。此外，相較於神經網路，XGBoost 在此規模的結構化交易資料（<65K 帳戶）訓練更快、超參數更穩定，且原生支援 scale_pos_weight 直接緩解 1:30 類別不平衡。\n\n【資料管線（AWS 端對端架構）】\n① BitoPro API 抓取交易紀錄 → ingest_to_s3.py 存入 AWS S3（原始資料層）\n② AWS Glue 執行 ETL 清洗 + glue_graph_hops.py 進行圖形化多跳關聯分析\n③ Amazon Athena 以 SQL 查詢聚合特徵結果（athena_graph_hops.sql）\n④ Amazon SageMaker 執行 XGBoost 模型訓練、超參數調整與模型部署\n⑤ AWS Lambda + lambda_diagnosis.py 處理即時推論與事件觸發邏輯\n⑥ Amazon Bedrock 整合 SHAP + XAI，為每筆高風險帳戶自動產生可解釋性報告\n⑦ Streamlit 儀表板（app.py）提供互動式風險審查介面\n⑧ CloudFormation template.yaml 定義全套 IaC（基礎設施即程式碼）\n\n【特徵工程（31 項行為指標）】\n競賽提交版以三項核心特徵起步（台幣存提次數、深夜交易比例），競賽後持續擴充至 31 項，涵蓋：\n・交易行為：total_volume、tx_per_day、avg_twd_amount、swap_twd_volume\n・時序特徵：min_retention_minutes（最短持幣時間）、night_tx_ratio\n・圖論特徵：blacklist_neighbor_count（黑名單鄰居數）、is_direct_neighbor\n・風險旗標：high_speed_risk、ip_anomaly、deposit_only_flag\n特徵重要性最高的前三名依序為：total_volume（交易總量）、age（帳戶年齡）、swap_twd_volume（換匯金額）\n\n【模型設計】\n・XGBoost（max_depth=8, lr=0.05, 1000 rounds, early stopping=30）\n・5-fold Stratified CV，確保每折正負樣本比例一致\n・scale_pos_weight 與決策閾值（0.3–0.9 掃描）調整，緩解 1:30 類別不平衡\n・SHAP 值分析呈現每個特徵對個別帳戶預測的貢獻度", "outcome": "【競賽成果】\n・完賽 AWS x BitoPro 黑客松，端對端雲端架構設計獲評審正面評價\n・81 commits，完整實作從 API 資料擷取到模型預測的全管線\n\n【技術成果】\n・成功串接六項 AWS 服務：SageMaker、Glue、Athena、Lambda、S3、Bedrock\n・特徵工程從競賽初版 3 項擴充至 31 項行為指標\n・SHAP 可解釋性模組讓模型判斷具備合規說明能力\n・Streamlit 儀表板支援帳戶風險互動審查，已部署上線\n\n【模型效能（5-fold Stratified CV）】\n・Precision：9.83%（± 8.12%）\n・Recall：0.43%（± 0.36%）\n・F1 Score：0.82%\n競賽提交版採保守閾值（0.65），共標記 2 個高風險帳戶——此設計決策刻意偏向 Precision，避免對正常用戶的誤判造成合規風險。\n\n【誠實的技術反思：為什麼這些指標是合理的起點？】\n低 Recall 直接反映 AML 場景的三重難題：① 標記樣本僅佔 3.21%（1:30 不平衡）；② 競賽資料集欠缺設備指紋、IP 關聯等高判別力特徵；③ 人頭帳戶的行為模式與正常高頻交易者高度重疊。真實金融機構的 AML 系統同樣面臨 Precision vs. Recall 的根本取捨——提高 Recall 必然增加誤報成本與人工審查負擔。後續改良方向：圖神經網路（GNN）建模黑名單鄰居關係、SMOTE/ADASYN 處理不平衡、擴充帳戶年齡與 IP 共用特徵。", "tech": [{"group": "機器學習", "items": [{"name": "梯度提升二元分類", "desc": "以 XGBoost（depth=8, 1000 rounds, early stopping）處理 1:30 類別不平衡，掌握 scale_pos_weight 設定與 0.3–0.9 閾值掃描對 Precision-Recall 曲線的影響"}, {"name": "行為特徵工程", "desc": "從台幣與 USDT 交易記錄中萃取 31 項行為指標（交易頻率、深夜比例、黑名單鄰居數等），驗證特徵從初版 3 項擴充後對模型的實際增益"}, {"name": "SHAP 可解釋性", "desc": "計算每筆帳戶各特徵的邊際貢獻，區分特徵重要性（全局）與個別帳戶判斷依據（局部），使模型結果具備 AML 合規說明能力"}]}, {"group": "雲端架構", "items": [{"name": "端對端資料管線", "desc": "設計 S3 → Glue ETL → Athena → SageMaker → Lambda 六服務串接，掌握各節點的資料格式轉換、錯誤傳遞與權限設計；CloudFormation IaC 確保環境可重現"}, {"name": "圖形化多跳關聯分析", "desc": "以 Glue + Athena SQL 實作黑名單鄰居的二階連結查詢，理解圖論特徵在關聯式資料庫中的近似計算方式與查詢複雜度"}, {"name": "事件驅動推論", "desc": "Lambda 接收觸發事件後呼叫 SageMaker 端點完成即時預測，理解冷啟動延遲與同步/非同步呼叫對 AML 即時偵測場景的取捨"}]}], "github": "https://github.com/Jcsk7049/bitoguard-aml", "demo": "https://bitoguard-aml-kykw6kfawalbeq8vjy6yv8.streamlit.app/"}}', '{"id": "aws-hackathon", "cover": "/images/AWS-bito-guard/dashboard-cover.png", "category": "大學校外作品", "title": "AWS × BitoPro Hackathon: BitOGuard", "period": "2026", "description": "XGBoost/LightGBM × S3→Glue→Athena→SageMaker→Lambda→Bedrock end-to-end AML pipeline; 63,770 accounts / 413,235 transactions; 31 behavioral features (incl. graph-theory blacklist neighbors) + SHAP compliance reports to identify money mule accounts. Streamlit dashboard live.", "tags": ["XGBoost", "LightGBM", "AWS SageMaker", "AWS Glue", "SHAP", "Streamlit"], "detail": {"images": [{"src": "/images/AWS-bito-guard/dashboard-overview.png", "caption": "Dashboard overview: AUC 83.2%, Precision 27.5%, Recall 33.2%, confusion matrix + 5-fold CV bar chart"}, {"src": "/images/AWS-bito-guard/dashboard-risk-query.png", "caption": "Account risk query: USER ID 971465 scored 82.1% — classified as extreme high risk, blacklisted"}, {"src": "/images/AWS-bito-guard/dashboard-risk-table.png", "caption": "Risk ranking: Top 50 high-risk (CRITICAL) vs. Top 50 low-risk accounts"}, {"src": "/images/AWS-bito-guard/dashboard-model-eval.png", "caption": "Model evaluation: feature importance (total_volume highest) + decision threshold analysis (optimal 0.24)"}, {"src": "/images/AWS-bito-guard/dashboard-predictions.png", "caption": "Predictions: 12,753 users — 501 flagged as risk (3.93%), 12,252 normal (96.07%)"}], "purpose": "BitoPro cryptocurrency exchange AML compliance competition dataset:\n- User records: 63,770 accounts\n- TWD transfer records: 195,601 (56,111 users)\n- USDT transaction records: 217,634 (33,587 users)\n- Labeled money mule accounts: 1,640 (3.21% of training set)\n\nGoal: output a risk score per account to identify high-risk suspicious accounts while satisfying regulators'' demand for explainability in AML compliance (black-box outputs not accepted).\n\nWhy XGBoost over deep learning:\nAML compliance requires feature-level justification for every flagged account. XGBoost + SHAP directly outputs each feature''s contribution per account, satisfying compliance reporting obligations. On <65K structured data, XGBoost also trains faster and is more stable than neural networks.", "concept": "[Why XGBoost, Not Deep Learning?]\nAML compliance systems require explainability: regulators demand \"which features triggered high risk\" for every flagged account. XGBoost with SHAP values directly outputs per-feature contributions for individual accounts, meeting compliance reporting requirements. On this scale of structured transactional data (<65K accounts), XGBoost also trains faster with more stable hyperparameters and natively supports scale_pos_weight to handle 1:30 class imbalance.\n\n[Data Pipeline — AWS End-to-End Architecture]\n① BitoPro API ingestion → ingest_to_s3.py → AWS S3 (raw data layer)\n② AWS Glue ETL + glue_graph_hops.py for graph-based multi-hop association analysis\n③ Amazon Athena SQL queries to aggregate feature results (athena_graph_hops.sql)\n④ Amazon SageMaker for XGBoost model training, hyperparameter tuning, and deployment\n⑤ AWS Lambda + lambda_diagnosis.py for real-time inference and event-driven logic\n⑥ Amazon Bedrock integrates SHAP + XAI to auto-generate explainability reports per high-risk account\n⑦ Streamlit dashboard (app.py) for interactive risk review\n⑧ CloudFormation template.yaml defines full IaC\n\n[Feature Engineering — 31 Behavioral Indicators]\nCompetition version started with 3 core features (TWD deposit/withdrawal count, late-night transaction ratio), expanded post-competition to 31 indicators:\n- Transaction behavior: total_volume, tx_per_day, avg_twd_amount, swap_twd_volume\n- Temporal features: min_retention_minutes, night_tx_ratio\n- Graph features: blacklist_neighbor_count, is_direct_neighbor\n- Risk flags: high_speed_risk, ip_anomaly, deposit_only_flag\nTop 3 by importance: total_volume, account age, swap_twd_volume\n\n[Model Design]\n- XGBoost (max_depth=8, lr=0.05, 1000 rounds, early stopping=30)\n- 5-fold Stratified CV with consistent positive/negative ratios per fold\n- scale_pos_weight + threshold sweep (0.3–0.9) to mitigate 1:30 imbalance\n- SHAP analysis shows per-feature contribution for individual accounts", "outcome": "[Competition Result]\n- Completed AWS × BitoPro Hackathon; end-to-end cloud architecture received positive feedback from judges\n- 81 commits, fully implementing the pipeline from API data ingestion to model prediction\n\n[Technical Achievements]\n- Successfully chained 6 AWS services: SageMaker, Glue, Athena, Lambda, S3, Bedrock\n- Feature engineering expanded from 3 competition features to 31 behavioral indicators\n- SHAP interpretability module provides AML-compliant explanations\n- Streamlit dashboard supports interactive account risk review — deployed live\n\n[Model Performance — 5-fold Stratified CV]\n- Precision: 9.83% (±8.12%)\n- Recall: 0.43% (±0.36%)\n- F1 Score: 0.82%\nCompetition submission used a conservative threshold (0.65), flagging only 2 high-risk accounts — intentionally biased toward precision to avoid false positives against legitimate users.\n\n[Honest Technical Reflection: Why These Metrics Are a Reasonable Starting Point]\nLow recall directly reflects AML''s triple challenge: ① only 3.21% labeled samples (1:30 imbalance); ② dataset lacks high-discriminating features like device fingerprints and IP associations; ③ money mule behavior patterns heavily overlap with legitimate high-frequency traders. Real financial AML systems face the same fundamental Precision vs. Recall tradeoff. Future improvements: graph neural networks (GNN) for blacklist neighbor relationships, SMOTE/ADASYN for imbalance, expanded account age and IP-sharing features.", "tech": [{"group": "Machine Learning", "items": [{"name": "Gradient Boosting Classification", "desc": "XGBoost (depth=8, 1000 rounds, early stopping) for 1:30 class imbalance; mastering scale_pos_weight configuration and 0.3–0.9 threshold sweeps'' effect on the Precision-Recall curve"}, {"name": "Behavioral Feature Engineering", "desc": "Extracting 31 behavioral indicators from TWD and USDT transaction records (frequency, late-night ratio, blacklist neighbor count, etc.), verifying actual model gains from expanding the initial 3-feature set"}, {"name": "SHAP Interpretability", "desc": "Computing each feature''s marginal contribution per account; distinguishing global feature importance from per-account local explanations to support AML compliance reporting"}]}, {"group": "Cloud Architecture", "items": [{"name": "End-to-End Data Pipeline", "desc": "Designed S3→Glue ETL→Athena→SageMaker→Lambda 6-service chain; mastering data format transformation, error propagation, and permission design between nodes; CloudFormation IaC for reproducibility"}, {"name": "Graph-Based Multi-hop Analysis", "desc": "Glue + Athena SQL for second-degree blacklist neighbor query; understanding the approximate computation of graph-theory features in relational databases and query complexity"}, {"name": "Event-Driven Inference", "desc": "Lambda receives trigger events and calls SageMaker endpoints for real-time prediction; understanding cold-start latency and sync/async tradeoffs for AML real-time detection"}]}], "github": "https://github.com/Jcsk7049/bitoguard-aml", "demo": "https://bitoguard-aml-kykw6kfawalbeq8vjy6yv8.streamlit.app/"}}', 3);
INSERT OR REPLACE INTO projects (id, zh, en, sort_order) VALUES ('audio-amplifier', '{"id": "audio-amplifier", "cover": "/images/audio-amplifier/circuit-assembled.jpg", "category": "大學課程作品", "title": "類比電路實作：音訊放大器 PCB 設計", "period": "2024", "description": "大二課程專案，建立基礎硬體素養：電路圖判讀、通孔元件焊接與基礎 PCB 佈線拓撲，實作兩級 BJT 音訊放大電路（CE + CC 架構）。完成感光板蝕刻製程，歷經兩次系統性除錯（分別診斷殘銅短路與元件腳位鏡像問題），最終順利驅動 8Ω 喇叭。", "tags": ["BJT 放大電路", "PCB Layout", "感光板製作", "電路模擬", "SPICE"], "detail": {"images": [{"src": "/images/audio-amplifier/circuit-assembled.jpg", "caption": "完成品：BJT 兩級放大電路板 + 8Ω 喇叭，實際驅動音訊輸出"}, {"src": "/images/audio-amplifier/pcb-etched.png", "caption": "感光板酸洗蝕刻後的 PCB 生板：走線清晰，準備鑽孔焊接"}, {"src": "/images/audio-amplifier/circuit-schematic.png", "caption": "EDA 電路原理圖：CE 放大級 + 偏壓網路 + CC 射極隨耦器完整設計"}, {"src": "/images/audio-amplifier/pcb-layout-components.png", "caption": "PCB 元件配置圖（正面）：109.2 × 45.7 mm，含電晶體、電容、可變電阻佈局"}, {"src": "/images/audio-amplifier/pcb-layout-bottom.png", "caption": "PCB 元件配置圖（底面）：確認元件腳位鏡像方向，兩次重製的關鍵學習點"}, {"src": "/images/audio-amplifier/pcb-traces.png", "caption": "PCB 銅箔走線圖：CE 放大級 + CC 射極隨耦器完整佈線"}, {"src": "/images/audio-amplifier/pcb-drill-pattern.png", "caption": "PCB 鑽孔孔位圖：所有元件腳位與固定孔的加工基準"}], "purpose": "大二電子學期末專案（第 12 組），目標是設計並實作一套可驅動 8Ω 喇叭的音訊放大電路。電路需包含可調增益功能，並完成從電路模擬、麵包板驗證到實際 PCB 製作的完整流程。\n\n分工：隊友負責麵包板驗證與 PSpice 模擬；我負責後段全部實作——邏輯圖與線路圖繪製、感光板製作（曝光、顯影、酸洗）、鑽孔、焊接與兩輪除錯。", "concept": "【電路架構：兩級 BJT 放大】\n・輸入級：可變電阻 Rv1a / Rv1b 調整輸入增益；R3 / R4 提供直流偏壓使 Q1 穩定工作於主動區\n・第一級 CE（共射極）放大：Q1 提供主要電壓增益，集極電阻 RC 將電流變化轉換為輸出電壓\n・偏壓穩定：D1–D4 四個二極體串聯穩定 Q2、Q3 基極電壓差；C3 吸收反向電壓避免二極體擊穿\n・第二級 CC（共集極 / 射極隨耦器）：高輸入阻抗、低輸出阻抗，透過發射極電阻 RE 的負回授提升穩定性並降低失真，電壓增益約為 1\n・可變電阻 Rv2 調整整體直流工作點，在不失真的條件下找到最大增益\n\n【PCB 製作流程】\n感光 FR4 雙面板（15 cm × 12.5 cm），手工製作流程：\n① Layout 繪製 → 縮減白線交叉點，元件下方走線壓縮面積\n② 底片輸出 → 曝光 → 顯影 → 酸洗蝕刻 → 清洗\n③ 鑽孔 → 元件焊接 → 通電測試\n\n【兩次重製過程】\n第一次失敗：酸洗後有殘銅未清除乾淨，通電後短路。逐一確認二極體導通、電晶體工作狀態均正常後，確認問題出在板子本身。重新繪製 Layout 加急重製。\n\n第二次問題：焊接完成後仍無法運作。隊友發現 PCB 圖紙需「從下往上看」——功率 IC 和電晶體腳位全數鏡像，重新焊接後電路出現斷續訊號且電壓五秒後下跌。再次確認所有焊點導通後，電路順暢運作。", "outcome": "・電路成功驅動 8Ω 實驗用小喇叭，輸出清晰音訊\n・完成從電路模擬、麵包板驗證到 PCB 實作的完整流程\n・電源：12V DC 電源供應器 / 9V 電池（外出場合）\n・輸入：3.5mm 雙公頭音源線連接電腦\n\n【個人心得】\n這次專題讓我清楚了解一個簡單的音訊放大原理，更加深了 PCB 製程的實戰能力。兩次重製過程中學到最多的不是設計本身，而是系統性除錯的方法——從元件逐一驗證到最終確認是腳位鏡像問題，每一步都需要對電路行為有清楚的預期，才能排除非預期狀況。", "tech": [{"group": "類比電路設計", "items": [{"name": "CE 放大器偏壓設計", "desc": "計算 R3 / R4 分壓偏壓使 Q1 穩定工作於主動區，理解 β 值、直流工作點與熱穩定度三者在選值時的取捨"}, {"name": "CC 射極隨耦器", "desc": "以發射極電阻 RE 引入負回授實現低輸出阻抗，有效降低前後級的負載效應，電壓增益接近 1"}, {"name": "偏壓穩定設計", "desc": "D1–D4 串聯提供穩定電壓差給 Q2/Q3 基極；C3 吸收關斷瞬間反向電壓，理解二極體正向壓降的溫度特性對偏壓穩定度的影響"}, {"name": "可變增益調整", "desc": "Rv1a/Rv1b 控制輸入信號強度，Rv2 微調直流工作點，實驗中在不失真前提下找到最大線性增益的操作邊界"}]}, {"group": "PCB 製作", "items": [{"name": "Layout 佈線設計", "desc": "手工繪製雙面 PCB，以元件下方走線策略減少白線交叉點，實際走完曝光→顯影→酸洗蝕刻製程"}, {"name": "系統性電路除錯", "desc": "兩次重製建立從元件逐一驗證（導通、飽和、充能）到板層短路定位的除錯流程，分別識別殘銅短路與腳位鏡像兩種根本原因"}]}, {"group": "量測與驗證", "items": [{"name": "電路模擬與實測對比", "desc": "先以 SPICE 模擬時域波形與頻率響應波德圖，再以示波器量測實際輸出，分析非理想元件特性（電阻溫度係數、電容漏電流）對結果造成的偏差"}]}], "github": ""}}', '{"id": "audio-amplifier", "cover": "/images/audio-amplifier/circuit-assembled.jpg", "category": "大學課程作品", "title": "Analog Circuit Implementation: Audio Amplifier PCB Design", "period": "2024", "description": "Sophomore course project building foundational hardware literacy: schematic reading and interpretation, through-hole soldering, and basic PCB routing topology for a two-stage BJT audio amplifier (CE + CC). Completed the full photoresist-etching fabrication flow and hands-on systematic debugging — rebuilt twice, diagnosing a residual-copper short and a component pin mirror error, before successfully driving an 8Ω speaker.", "tags": ["BJT Amplifier", "PCB Layout", "Photoresist Etching", "Circuit Simulation", "SPICE"], "detail": {"images": [{"src": "/images/audio-amplifier/circuit-assembled.jpg", "caption": "Final product: two-stage BJT amplifier board + 8Ω speaker, driving audio output"}, {"src": "/images/audio-amplifier/pcb-etched.png", "caption": "Photoresist-etched PCB blank: clear traces, ready for drilling and soldering"}, {"src": "/images/audio-amplifier/circuit-schematic.png", "caption": "EDA schematic: CE amplifier stage + bias network + CC emitter follower"}, {"src": "/images/audio-amplifier/pcb-layout-components.png", "caption": "PCB component placement (top): 109.2×45.7mm, transistors, capacitors, trimpots"}, {"src": "/images/audio-amplifier/pcb-layout-bottom.png", "caption": "PCB component placement (bottom): confirming mirrored pin orientation — key lesson from two rebuilds"}, {"src": "/images/audio-amplifier/pcb-traces.png", "caption": "PCB copper traces: full routing for CE + CC stages"}, {"src": "/images/audio-amplifier/pcb-drill-pattern.png", "caption": "PCB drill pattern: all component pads and mounting hole machining reference"}], "purpose": "Sophomore Electronics final project (Group 12): design and implement an audio amplifier circuit capable of driving an 8Ω speaker. The circuit needed adjustable gain and required completing the full flow from circuit simulation and breadboard verification to actual PCB fabrication.\n\nDivision of work: a teammate handled breadboard verification and PSpice simulation; I did everything after that — schematic drawing, photoresist board fabrication (exposure, development, etching), drilling, soldering, and both rounds of debugging.", "concept": "[Circuit Topology: Two-Stage BJT Amplification]\n- Input stage: trimpots Rv1a/Rv1b adjust input gain; R3/R4 DC bias stabilizes Q1 in active region\n- First stage — CE (Common Emitter): Q1 provides main voltage gain; collector resistor RC converts current changes to output voltage\n- Bias stabilization: D1–D4 (4 series diodes) stabilize base voltage for Q2/Q3; C3 absorbs reverse voltage spikes to prevent diode breakdown\n- Second stage — CC (Common Collector / Emitter Follower): high input impedance, low output impedance; emitter resistor RE provides negative feedback for stability and low distortion, voltage gain ≈1\n- Trimpot Rv2 adjusts overall DC operating point to find maximum gain without distortion\n\n[PCB Fabrication Flow]\nPhotosensitive FR4 double-sided board (15cm × 12.5cm), hand-fabricated:\n① Layout → minimize white-line crossings, compress routing under components\n② Film output → exposure → development → acid etching → rinse\n③ Drilling → component soldering → power-on testing\n\n[Two Rebuilds]\nFirst failure: residual copper after acid etching caused shorts. After verifying all diodes conducting and transistors operating normally, confirmed the board itself was the issue. Redesigned layout and urgently rebuilt.\n\nSecond problem: circuit still non-functional after soldering. Teammate discovered that PCB artwork must be viewed \"from below\" — all power IC and transistor pins were mirrored. After re-soldering, circuit showed intermittent signal with voltage dropping after 5 seconds. After confirming all solder joint continuity, the circuit operated smoothly.", "outcome": "- Circuit successfully drives an 8Ω laboratory speaker with clear audio output\n- Completed the full flow: circuit simulation → breadboard verification → PCB fabrication\n- Power: 12V DC power supply / 9V battery (portable use)\n- Input: 3.5mm stereo cable from computer\n\n[Personal Reflection]\nThis project gave me a clear understanding of audio amplification principles and deepened my hands-on PCB fabrication skills. The two rebuilds taught me the most — not about design itself, but about systematic debugging: from component-by-component verification to finally identifying the pin mirror issue. Each step required a clear expectation of circuit behavior to eliminate unexpected conditions.", "tech": [{"group": "Analog Circuit Design", "items": [{"name": "CE Amplifier Bias Design", "desc": "Calculating R3/R4 voltage divider bias to stabilize Q1 in active region; understanding the tradeoffs between β, DC operating point, and thermal stability in component selection"}, {"name": "CC Emitter Follower", "desc": "Emitter resistor RE introduces negative feedback for low output impedance, reducing loading effects between stages; voltage gain approaches 1"}, {"name": "Bias Stabilization Design", "desc": "D1–D4 in series provide stable voltage difference to Q2/Q3 bases; C3 absorbs turn-off transient reverse voltage; understanding how diode forward voltage temperature characteristics affect bias stability"}, {"name": "Variable Gain Adjustment", "desc": "Rv1a/Rv1b control input signal strength; Rv2 fine-tunes DC operating point; experimentally finding the maximum linear gain boundary without distortion"}]}, {"group": "PCB Fabrication", "items": [{"name": "Layout Routing Design", "desc": "Hand-drawn double-sided PCB; routing under components to reduce white-line crossings; completed full exposure→development→acid etching process"}, {"name": "Systematic Circuit Debugging", "desc": "Two rebuilds established a debugging flow from component-by-component verification (continuity, saturation, charge) to board-layer short detection; identified residual-copper shorts and pin mirror errors as root causes"}]}, {"group": "Measurement & Verification", "items": [{"name": "Simulation vs. Real-World Comparison", "desc": "SPICE simulation of time-domain waveform and Bode plot frequency response, then oscilloscope measurement of actual output; analyzing deviations caused by non-ideal component characteristics"}]}], "github": ""}}', 4);
INSERT OR REPLACE INTO projects (id, zh, en, sort_order) VALUES ('pcb-defect-detection', '{"id": "pcb-defect-detection", "cover": "/images/pcb-defect-detection/cover.png", "category": "大學課程作品", "title": "PCB 線路瑕疵偵測：Azure Custom Vision 切塊物件偵測", "period": "2026", "description": "北大 PCB 瑕疵資料集，挑 6 個板型（01／04／05／06／07／08）× 3 種缺陷（missing_hole 缺孔、mouse_bite 鼠咬、open_circuit 斷路）訓練物件偵測。原圖是 3034×1586 的整板、缺陷框只有約 60px，直接丟 Custom Vision 會被縮到約 512px 而看不見，第一次訓練 mAP 只有 9.6%、Recall 3.1%。改成把大圖切成 600px 小塊再訓練後，mAP 88.2%、Precision 100%。匯出 TensorFlow model.pb，可在 Colab 載入推論。 另把模型包成本機檢測工具，支援批量上傳、缺陷統計與 CSV，並設計「人工回饋→審核→重訓」的 active-learning 迴圈。（AI 輔助開發）", "tags": ["Azure Custom Vision", "Object Detection", "影像切塊 Tiling", "model.pb · TensorFlow", "Pascal VOC"], "detail": {"images": [{"src": "/images/pcb-defect-detection/performance.png", "caption": "Advanced Training 成果（6 板型）：整體 Precision 100% / Recall 72.3% / mAP 88.2%（threshold 0.5），分缺陷數據見下方"}, {"src": "/images/pcb-defect-detection/pipeline.png", "caption": "檢測工具與人工回饋重訓流程：上傳→切塊偵測→批量統計→人工校正→審核核准→只用核准資料重訓"}, {"src": "/images/pcb-defect-detection/dataset.png", "caption": "訓練資料：每張大圖以缺陷為中心切成 600px 塊，缺陷框佔比從約 2% 拉到約 12%（綠框為標註）"}, {"src": "/images/pcb-defect-detection/validation-zoom.png", "caption": "未參與訓練的板型 09–12 驗證（放大）：綠＝標註、紅＝模型預測，三類缺陷定位清楚"}, {"src": "/images/pcb-defect-detection/validation-board.png", "caption": "整板偵測：對 held-out 板（型號 09）做切塊推論後把框映射回原圖的完整結果"}, {"src": "/images/pcb-defect-detection/missing-hole/09_01.jpg", "caption": "missing_hole 偵測：板型 09 第 1 張（綠＝標註，紅＝模型預測）"}, {"src": "/images/pcb-defect-detection/missing-hole/09_02.jpg", "caption": "missing_hole 偵測：板型 09 第 2 張（綠＝標註，紅＝模型預測）"}, {"src": "/images/pcb-defect-detection/missing-hole/09_03.jpg", "caption": "missing_hole 偵測：板型 09 第 3 張（綠＝標註，紅＝模型預測）"}, {"src": "/images/pcb-defect-detection/missing-hole/09_04.jpg", "caption": "missing_hole 偵測：板型 09 第 4 張（綠＝標註，紅＝模型預測）"}, {"src": "/images/pcb-defect-detection/missing-hole/09_05.jpg", "caption": "missing_hole 偵測：板型 09 第 5 張（綠＝標註，紅＝模型預測）"}, {"src": "/images/pcb-defect-detection/missing-hole/09_06.jpg", "caption": "missing_hole 偵測：板型 09 第 6 張（綠＝標註，紅＝模型預測）"}, {"src": "/images/pcb-defect-detection/missing-hole/09_07.jpg", "caption": "missing_hole 偵測：板型 09 第 7 張（綠＝標註，紅＝模型預測）"}, {"src": "/images/pcb-defect-detection/missing-hole/09_08.jpg", "caption": "missing_hole 偵測：板型 09 第 8 張（綠＝標註，紅＝模型預測）"}, {"src": "/images/pcb-defect-detection/missing-hole/09_09.jpg", "caption": "missing_hole 偵測：板型 09 第 9 張（綠＝標註，紅＝模型預測）"}, {"src": "/images/pcb-defect-detection/missing-hole/09_10.jpg", "caption": "missing_hole 偵測：板型 09 第 10 張（綠＝標註，紅＝模型預測）"}, {"src": "/images/pcb-defect-detection/missing-hole/10_01.jpg", "caption": "missing_hole 偵測：板型 10 第 1 張（綠＝標註，紅＝模型預測）"}, {"src": "/images/pcb-defect-detection/missing-hole/10_02.jpg", "caption": "missing_hole 偵測：板型 10 第 2 張（綠＝標註，紅＝模型預測）"}, {"src": "/images/pcb-defect-detection/missing-hole/10_03.jpg", "caption": "missing_hole 偵測：板型 10 第 3 張（綠＝標註，紅＝模型預測）"}, {"src": "/images/pcb-defect-detection/missing-hole/10_04.jpg", "caption": "missing_hole 偵測：板型 10 第 4 張（綠＝標註，紅＝模型預測）"}, {"src": "/images/pcb-defect-detection/missing-hole/10_05.jpg", "caption": "missing_hole 偵測：板型 10 第 5 張（綠＝標註，紅＝模型預測）"}, {"src": "/images/pcb-defect-detection/missing-hole/11_01.jpg", "caption": "missing_hole 偵測：板型 11 第 1 張（綠＝標註，紅＝模型預測）"}, {"src": "/images/pcb-defect-detection/missing-hole/11_02.jpg", "caption": "missing_hole 偵測：板型 11 第 2 張（綠＝標註，紅＝模型預測）"}, {"src": "/images/pcb-defect-detection/missing-hole/11_03.jpg", "caption": "missing_hole 偵測：板型 11 第 3 張（綠＝標註，紅＝模型預測）"}, {"src": "/images/pcb-defect-detection/missing-hole/11_04.jpg", "caption": "missing_hole 偵測：板型 11 第 4 張（綠＝標註，紅＝模型預測）"}, {"src": "/images/pcb-defect-detection/missing-hole/11_05.jpg", "caption": "missing_hole 偵測：板型 11 第 5 張（綠＝標註，紅＝模型預測）"}, {"src": "/images/pcb-defect-detection/missing-hole/11_06.jpg", "caption": "missing_hole 偵測：板型 11 第 6 張（綠＝標註，紅＝模型預測）"}, {"src": "/images/pcb-defect-detection/missing-hole/11_07.jpg", "caption": "missing_hole 偵測：板型 11 第 